class Command(BaseCommand):
    help = 'Add more questions to existing rooms'

    def handle(self, *args, **options):
        total_added = 0

        for room_name, data in MORE_QUESTIONS.items():
            try:
                room = Room.objects.get(name=room_name)
            except Room.DoesNotExist:
                self.stdout.write(f'Room not found: {room_name} — skipping')
                continue

            self.stdout.write(f'Adding questions to: {room_name}')

            for difficulty, questions in [('easy', data['easy']), ('hard', data['hard'])]:
                for q in questions:
                    _, created = Question.objects.get_or_create(
                        room=room,
                        text=q['text'],
                        difficulty=difficulty,
                        defaults={
                            'option_a': q['option_a'],
                            'option_b': q['option_b'],
                            'option_c': q['option_c'],
                            'option_d': q['option_d'],
                            'correct_answer': q['correct_answer'],
                        }
                    )
                    if created:
                        total_added += 1

        self.stdout.write(
            self.style.SUCCESS(f'Done. Added {total_added} new questions.')
        )
